            <div className="table-container">
              <table className="table">
                <thead>
                  <tr>
                    <th>Código</th>
                    <th>Descripción</th>
                    <th>Estado</th>
                    <th>Precio</th>
                    <th style={{ textAlign: 'right' }}>Ver</th>
                  </tr>
                </thead>
                <tbody>
                  {client.projects.map(p => {
                    const paid = p.payments.reduce((sum, pay) => sum + pay.amount, 0);
                    const debt = p.agreedPrice - paid;
                    return (
                      <tr key={p.id}>
                        <td>
                          <span style={{ fontWeight: 600 }}>{p.projectNumber}</span>
                        </td>
                        <td style={{ maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={p.description}>
                          {p.description}
                        </td>
                        <td>
                          <span className={`badge ${
                            p.status === 'entregado' ? 'badge-success' : 
                            p.status === 'cancelado' ? 'badge-danger' : 
                            p.status === 'presupuesto' ? 'badge-secondary' : 'badge-primary'
                          }`}>
                            {p.status}
                          </span>
                        </td>
                        <td>
                          <div style={{ fontWeight: 600 }}>{formatARS(p.agreedPrice)}</div>
                          {debt > 0 && <div style={{ fontSize: '0.75rem', color: 'var(--error-color)' }}>Debe {formatARS(debt)}</div>}
                        </td>
                        <td style={{ textAlign: 'right' }}>
                          <Link href={`/proyectos/${p.id}`} className="btn btn-secondary btn-sm" style={{ padding: '6px' }}>
                            <Eye size={14} />
                          </Link>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Payments History */}
        <div className="card">
          <div className="card-header" style={{ marginBottom: '15px' }}>
            <h3 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <FileText size={20} style={{ color: 'var(--success-color)' }} />
              Historial de Pagos Recibidos
            </h3>
            <span className="badge badge-success">{allPayments.length}</span>
          </div>
          {allPayments.length === 0 ? (
            <p style={{ color: 'var(--text-muted)', padding: '20px 0', textAlign: 'center' }}>No se registran cobros para este cliente.</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {allPayments.map(p => (
                <div key={p.id} style={{ padding: '12px', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-sm)', backgroundColor: 'var(--bg-color)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', display: 'block' }}>
                      {new Date(p.date).toLocaleDateString('es-AR')}
                    </span>
                    <span style={{ fontSize: '0.85rem', fontWeight: 600 }}>
                      Pago Proyecto {p.projectNumber}
                    </span>
                    {p.notes && <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '2px' }}>{p.notes}</p>}
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <span style={{ fontWeight: 700, color: 'var(--success-color)', display: 'block', fontSize: '0.95rem' }}>
                      +{formatARS(p.amount)}
                    </span>
                    <span className="badge badge-primary" style={{ fontSize: '0.65rem', padding: '2px 6px', marginTop: '2px', display: 'inline-block' }}>
                      Método ID
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>

    </div>
  );
}

'use server';

import prisma from '@/lib/prisma';
import { createAuditLog } from '@/lib/audit';
import { revalidatePath } from 'next/cache';

export async function getEmployees() {
  try {
    return await prisma.employee.findMany({
      where: { deletedAt: null },
      orderBy: { name: 'asc' },
    });
  } catch (error) {
    console.error('Error al obtener empleados:', error);
    return [];
  }
}

export async function getEmployeeById(id: string) {
  try {
    return await prisma.employee.findUnique({
      where: { id },
      include: {
        workRecords: {
          where: { deletedAt: null },
          orderBy: { date: 'desc' },
          include: {
            project: true
          }
        }
      }
    });
  } catch (error) {
    console.error('Error al obtener empleado:', error);
    return null;
  }
}

export async function createEmployee(data: {
  name: string;
  phone?: string | null;
  email?: string | null;
  ratePerDay: number;
}) {
  try {
    const employee = await prisma.employee.create({
      data: {
        name: data.name,
        phone: data.phone || null,
        email: data.email || null,
        ratePerDay: data.ratePerDay,
        active: true,
      },
    });

    await createAuditLog('employees', employee.id, 'insert', null, employee);
    revalidatePath('/empleados');
    return { success: true, employee };
  } catch (error: any) {
    console.error('Error al crear empleado:', error);
    return { success: false, error: error.message || 'Error al crear empleado' };
  }
}

export async function updateEmployee(
  id: string,
  data: {
    name: string;
    phone?: string | null;
    email?: string | null;
    ratePerDay: number;
    active: boolean;
  }
) {
  try {
    const oldEmployee = await prisma.employee.findUnique({ where: { id } });
    if (!oldEmployee) return { success: false, error: 'Empleado no encontrado' };

    const employee = await prisma.employee.update({
      where: { id },
      data: {
        name: data.name,
        phone: data.phone || null,
        email: data.email || null,
        ratePerDay: data.ratePerDay,
        active: data.active,
      },
    });

    await createAuditLog('employees', employee.id, 'update', oldEmployee, employee);
    revalidatePath('/empleados');
    revalidatePath(`/empleados/${id}`);
    return { success: true, employee };
  } catch (error: any) {
    console.error('Error al actualizar empleado:', error);
    return { success: false, error: error.message || 'Error al actualizar empleado' };
  }
}

export async function deleteEmployee(id: string) {
  try {
    const oldEmployee = await prisma.employee.findUnique({ where: { id } });
    if (!oldEmployee) return { success: false, error: 'Empleado no encontrado' };

    // Soft delete
    const employee = await prisma.employee.update({
      where: { id },
      data: { deletedAt: new Date() },
    });

    await createAuditLog('employees', employee.id, 'delete', oldEmployee, { ...oldEmployee, deletedAt: employee.deletedAt });
    revalidatePath('/empleados');
    return { success: true };
  } catch (error: any) {
    console.error('Error al eliminar empleado:', error);
    return { success: false, error: error.message || 'Error al eliminar empleado' };
  }
}

// Obtener reporte de costos laborales consolidado
export async function getLaborCostReport(filters: {
  employeeId?: string;
  year?: number;
  month?: number;
}) {
  try {
    const whereClause: any = { deletedAt: null };

    if (filters.employeeId) {
      whereClause.employeeId = filters.employeeId;
    }

    if (filters.year && filters.month) {
      const start = new Date(filters.year, filters.month - 1, 1);
      const end = new Date(filters.year, filters.month, 0, 23, 59, 59);
      whereClause.date = { gte: start, lte: end };
    } else if (filters.year) {
      const start = new Date(filters.year, 0, 1);
      const end = new Date(filters.year, 11, 31, 23, 59, 59);
      whereClause.date = { gte: start, lte: end };
    }

    const records = await prisma.projectEmployee.findMany({
      where: whereClause,
      include: {
        employee: true,
        project: true
      },
      orderBy: { date: 'desc' }
    });

    return records;
  } catch (error) {
    console.error('Error al obtener reporte de costos laborales:', error);
    return [];
  }
}

