                      <td style={{ fontWeight: 500 }}>{rec.employee.name}</td>
                      <td>
                        <span style={{ fontWeight: 600 }}>{rec.project.projectNumber}</span>
                      </td>
                      <td>{rec.daysWorked} día(s)</td>
                      <td>{formatARS(rec.ratePerDay)}</td>
