export interface Part {
  length: number;
  width: number;
  qty: number;
  label: string;
  material: string;
  thickness: number;
  notes?: string;
}

export interface Sheet {
  length: number;
  width: number;
  qty: number;
  material: string;
  thickness: number;
  cost: number;
  notes?: string;
}

interface FreeRect {
  x: number;
  y: number;
  w: number;
  h: number;
}

export interface PlacedPart {
  x: number;
  y: number;
  w: number; // Placed width (might be rotated)
  h: number; // Placed length
  label: string;
  rotated: boolean;
  notes?: string;
}

export interface OptimizedSheetResult {
  sheetIndex: number;
  sheetWidth: number;
  sheetLength: number;
  cost: number;
  placedParts: PlacedPart[];
  freeSpaces: FreeRect[];
  utilizationArea: number;
  wasteArea: number;
  utilizationPercentage: number;
}

export interface OptimizationResult {
  results: OptimizedSheetResult[];
  unplacedParts: { label: string; qty: number; w: number; h: number }[];
  totals: {
    totalPartsPlaced: number;
    sheetsUsedCount: number;
    totalUsedArea: number;
    totalWastedArea: number;
    utilizationPercentage: number;
    totalSheetsCost: number;
    wastedCost: number;
  };
}

/**
 * Heurística de empaquetamiento 2D por corte de guillotina.
 * Ordena las piezas por área descendente y las coloca en los espacios libres
 * de las placas disponibles aplicando división horizontal o vertical.
 */
export function optimizeCuts(
  partsInput: Part[],
  sheetsInput: Sheet[],
  options: {
    kerf: number;
    edgeTrim: number;
    useGrain: boolean;
  }
): OptimizationResult {
  const { kerf, edgeTrim, useGrain } = options;

  // 1. Expandir las cantidades de las piezas en un listado plano e individual
  const flatParts: { w: number; h: number; label: string; notes?: string }[] = [];
  partsInput.forEach(p => {
    for (let i = 0; i < p.qty; i++) {
      flatParts.push({
        w: p.width,
        h: p.length,
        label: p.label || `Pieza ${flatParts.length + 1}`,
        notes: p.notes
      });
    }
  });

  // Ordenar piezas por superficie (área) de mayor a menor (mejor empaquetamiento)
  flatParts.sort((a, b) => (b.w * b.h) - (a.w * a.h));

  // 2. Expandir el listado de placas disponibles
  const flatSheets: { w: number; h: number; cost: number; originalIdx: number }[] = [];
  sheetsInput.forEach((s, idx) => {
    for (let i = 0; i < s.qty; i++) {
      flatSheets.push({
        w: s.width,
        h: s.length,
        cost: s.cost || 0,
        originalIdx: idx
      });
    }
  });

  const results: OptimizedSheetResult[] = [];
  const unplacedParts: { label: string; qty: number; w: number; h: number }[] = [];

  // Espacios libres por cada placa activa
  const sheetsFreeSpaces: FreeRect[][] = [];
  const sheetsPlacedParts: PlacedPart[][] = [];

  // Inicializar espacios libres para todas las placas (restando el refilado de bordes)
  flatSheets.forEach((sheet, sheetIdx) => {
    const doubleTrim = edgeTrim * 2;
    const usableW = sheet.w - doubleTrim;
    const usableH = sheet.h - doubleTrim;

    sheetsFreeSpaces.push([
      {
        x: edgeTrim,
        y: edgeTrim,
        w: usableW > 0 ? usableW : 0,
        h: usableH > 0 ? usableH : 0
      }
    ]);
    sheetsPlacedParts.push([]);
  });

  let activeSheetsCount = 0;
  const activeSheetsUsed = new Set<number>();

  // 3. Colocar cada pieza
  for (const part of flatParts) {
    let placed = false;

    // Buscar en las placas que ya hemos empezado a utilizar primero para no abrir placas de más
    const sheetsToTry = Array.from(activeSheetsUsed).sort((a, b) => a - b);

    // Si no entra en las ya activas, intentaremos con la primera placa vacía disponible
    for (let i = 0; i < flatSheets.length; i++) {
      if (!activeSheetsUsed.has(i) && sheetsToTry.indexOf(i) === -1) {
        sheetsToTry.push(i);
      }
    }

    for (const sheetIdx of sheetsToTry) {
      const freeSpaces = sheetsFreeSpaces[sheetIdx];

      // Buscar el primer espacio libre donde quepa la pieza
      let spaceIdx = -1;
      let rotatePart = false;

      for (let s = 0; s < freeSpaces.length; s++) {
        const space = freeSpaces[s];

        // Caso 1: Sin rotar
        if (part.w <= space.w && part.h <= space.h) {
          spaceIdx = s;
          rotatePart = false;
          break;
        }

        // Caso 2: Rotado (solo si no se exige respetar la veta/grano)
        if (!useGrain && part.h <= space.w && part.w <= space.h) {
          spaceIdx = s;
          rotatePart = true;
          break;
        }
      }

      // Si encontramos espacio, colocar la pieza y dividir el espacio restante
      if (spaceIdx !== -1) {
        const space = freeSpaces[spaceIdx];
        const pw = rotatePart ? part.h : part.w;
        const ph = rotatePart ? part.w : part.h;

        // Añadir pieza colocada
        sheetsPlacedParts[sheetIdx].push({
          x: space.x,
          y: space.y,
          w: pw,
          h: ph,
          label: part.label,
          rotated: rotatePart,
          notes: part.notes
        });

        // Marcar la placa como usada
        if (!activeSheetsUsed.has(sheetIdx)) {
          activeSheetsUsed.add(sheetIdx);
          activeSheetsCount++;
        }

        // Dividir el espacio restante usando corte de guillotina
        // Eliminamos el espacio usado
        freeSpaces.splice(spaceIdx, 1);

        // Generamos dos nuevos espacios resultantes de la subdivisión
        // Espacio a la derecha de la pieza colocada (incluyendo kerf)
        const rightW = space.w - pw - kerf;
        const rightH = ph; // Altura acotada a la pieza para un corte limpio
        if (rightW > 0 && rightH > 0) {
          freeSpaces.push({
            x: space.x + pw + kerf,
            y: space.y,
            w: rightW,
            h: rightH
          });
        }

        // Espacio arriba de la pieza colocada (incluyendo kerf)
        const topW = space.w;
        const topH = space.h - ph - kerf;
        if (topW > 0 && topH > 0) {
          freeSpaces.push({
            x: space.x,
            y: space.y + ph + kerf,
            w: topW,
            h: topH
          });
        }

        // Ordenar espacios libres por área descendente para maximizar encaje futuro
        freeSpaces.sort((a, b) => (b.w * b.h) - (a.w * a.h));
        placed = true;
        break;
      }
    }

    if (!placed) {
      // Registrar pieza que no cupo en ninguna placa
      const existing = unplacedParts.find(u => u.label === part.label && u.w === part.w && u.h === part.h);
      if (existing) {
        existing.qty++;
      } else {
        unplacedParts.push({ label: part.label, qty: 1, w: part.w, h: part.h });
      }
    }
  }

  // 4. Compilar resultados de las placas utilizadas
  let totalPartsPlaced = 0;
  let totalUsedArea = 0;
  let totalWastedArea = 0;
  let totalSheetsCost = 0;

  activeSheetsUsed.forEach(sheetIdx => {
    const sheet = flatSheets[sheetIdx];
    const placed = sheetsPlacedParts[sheetIdx];
    const free = sheetsFreeSpaces[sheetIdx];

    totalPartsPlaced += placed.length;
    totalSheetsCost += sheet.cost;

    // Área total de la placa
    const sheetTotalArea = sheet.w * sheet.h;

    // Área utilizada por piezas colocadas (suma de sus áreas individuales)
    const placedArea = placed.reduce((sum, p) => sum + (p.w * p.h), 0);
    totalUsedArea += placedArea;

    // Área desperdiciada (Toda el área que no es pieza colocada)
    const wasteArea = sheetTotalArea - placedArea;
    totalWastedArea += wasteArea;

    const utilizationPercentage = parseFloat(((placedArea / sheetTotalArea) * 100).toFixed(2));

    results.push({
      sheetIndex: sheetIdx + 1,
      sheetWidth: sheet.w,
      sheetLength: sheet.h,
      cost: sheet.cost,
      placedParts: placed,
      freeSpaces: free,
      utilizationArea: placedArea,
      wasteArea,
      utilizationPercentage
    });
  });

  const totalAreaAllUsedSheets = results.reduce((sum, r) => sum + (r.sheetWidth * r.sheetLength), 0);
  const globalUtilizationPct = totalAreaAllUsedSheets > 0 
    ? parseFloat(((totalUsedArea / totalAreaAllUsedSheets) * 100).toFixed(2))
    : 0;

  // Costo estimado del desperdicio
  const wastedCost = totalSheetsCost * (1 - (globalUtilizationPct / 100));

  return {
    results,
    unplacedParts,
    totals: {
      totalPartsPlaced,
      sheetsUsedCount: results.length,
      totalUsedArea,
      totalWastedArea,
      utilizationPercentage: globalUtilizationPct,
      totalSheetsCost,
      wastedCost: parseFloat(wastedCost.toFixed(2))
    }
  };
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  Play, 
  Save, 
  Check, 
  Trash2, 
  Plus, 
  Upload, 
  Download, 
  Maximize2, 
  Minimize2,
  AlertTriangle,
  Scissors,
  CheckCircle,
  FileText
} from 'lucide-react';
import { optimizeCuts, Part, Sheet, OptimizationResult } from '@/lib/cutlistOptimizer';
import { saveCutlist, confirmCutlistCuts } from '@/app/proyectos/actions';

interface CutlistOptimizerProps {
  projectId: string;
  materialCategories: any[];
  inventory: any[];
  initialCutlist: any;
  projectNumber: string;
  onConfirmSuccess?: () => void;
}

export default function CutlistOptimizer({
  projectId,
  materialCategories,
  inventory,
  initialCutlist,
  projectNumber,
  onConfirmSuccess
}: CutlistOptimizerProps) {
  // Config options
  const [kerf, setKerf] = useState(4);
  const [edgeTrim, setEdgeTrim] = useState(10);
  const [useGrain, setUseGrain] = useState(true);

  // Parts list
  const [parts, setParts] = useState<Part[]>([
    { length: 600, width: 400, qty: 4, label: 'Frente Cajón', material: 'Melamina Blanca', thickness: 18, notes: 'Veta horizontal' },
    { length: 800, width: 500, qty: 2, label: 'Lateral Módulo', material: 'Melamina Blanca', thickness: 18 }
  ]);

  // Hojas/Placas disponibles
  const [sheets, setSheets] = useState<Sheet[]>([
    { length: 2750, width: 1830, qty: 2, material: 'Melamina Blanca', thickness: 18, cost: 45000, notes: 'Placa estándar' }
  ]);

  // Results
  const [optimizationResult, setOptimizationResult] = useState<OptimizationResult | null>(null);

  // UI states
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
  const [zoomScale, setZoomScale] = useState(0.2); // Escala para renderizado SVG
  const [isConfirmed, setIsConfirmed] = useState(false);

  // Cargar datos guardados si existen
  useEffect(() => {
    if (initialCutlist) {
      try {
        setKerf(initialCutlist.kerf || 4);
        setEdgeTrim(initialCutlist.edgeTrim || 10);
        setUseGrain(initialCutlist.useGrain !== undefined ? initialCutlist.useGrain : true);
        if (initialCutlist.parts) setParts(JSON.parse(initialCutlist.parts));
        if (initialCutlist.sheets) setSheets(JSON.parse(initialCutlist.sheets));
        if (initialCutlist.results) setOptimizationResult(JSON.parse(initialCutlist.results));
      } catch (e) {
        console.error('Error al parsear cutlist guardado:', e);
      }
    }
  }, [initialCutlist]);

  // Cargar plantilla desde inventario para comodidad del usuario
  const handleLoadSheetFromInventory = (invItem: any) => {
    // Intentar extraer largo y ancho del nombre, ej: "2.75x1.83" -> 2750x1830
    let length = 2750;
    let width = 1830;
    const regex = /(\d+[\.,]\d+)\s*[xX]\s*(\d+[\.,]\d+)/;
    const match = invItem.name.match(regex);
    if (match) {
      length = Math.round(parseFloat(match[1].replace(',', '.')) * 1000);
      width = Math.round(parseFloat(match[2].replace(',', '.')) * 1000);
    }

    // Buscar si ya existe la placa del mismo material y tamaño
    const exists = sheets.find(s => s.material === invItem.name);
    if (exists) {
      alert('Esta placa ya está agregada en la lista de disponibles.');
      return;
    }

    setSheets(prev => [
      ...prev,
      {
        length,
        width,
        qty: invItem.currentStock || 1,
        material: invItem.name,
        thickness: 18, // Grosor estimado por defecto
        cost: invItem.unitCost,
        notes: `Vinculado a Stock (Id: ${invItem.id})`
      }
    ]);
  };

  // Agregar fila de piezas
  const handleAddPart = () => {
    setParts(prev => [
      ...prev,
      { length: 500, width: 300, qty: 1, label: `Pieza ${prev.length + 1}`, material: sheets[0]?.material || 'Melamina Blanca', thickness: 18 }
    ]);
  };

  // Remover fila de piezas
  const handleRemovePart = (idx: number) => {
    setParts(prev => prev.filter((_, i) => i !== idx));
  };

  // Editar valor de pieza
  const handleUpdatePart = (idx: number, field: keyof Part, value: any) => {
    setParts(prev => prev.map((p, i) => i === idx ? { ...p, [field]: value } : p));
  };

  // Agregar fila de placas
  const handleAddSheet = () => {
    setSheets(prev => [
      ...prev,
      { length: 2750, width: 1830, qty: 1, material: 'Melamina Blanca', thickness: 18, cost: 45000 }
    ]);
  };

  // Remover fila de placas
  const handleRemoveSheet = (idx: number) => {
    setSheets(prev => prev.filter((_, i) => i !== idx));
  };

  // Editar valor de placa
  const handleUpdateSheet = (idx: number, field: keyof Sheet, value: any) => {
    setSheets(prev => prev.map((s, i) => i === idx ? { ...s, [field]: value } : s));
  };

  // Ejecutar el algoritmo de empaquetamiento 2D
  const handleOptimize = () => {
    setMessage(null);
    if (parts.length === 0 || sheets.length === 0) {
      setMessage({ type: 'error', text: 'Debe cargar al menos una pieza y una placa disponible.' });
      return;
    }

    const result = optimizeCuts(parts, sheets, { kerf, edgeTrim, useGrain });
    setOptimizationResult(result);
    setIsConfirmed(false);
  };

  // Guardar configuración del Cutlist en base de datos
  const handleSaveCutlist = async () => {
    setLoading(true);
    setMessage(null);
    const res = await saveCutlist({
      projectId,
      kerf,
      edgeTrim,
      useGrain,
      parts,
      sheets,
      results: optimizationResult
    });

    if (res.success) {
      setMessage({ type: 'success', text: 'Configuración de corte guardada con éxito.' });
    } else {
      setMessage({ type: 'error', text: res.error || 'Error al guardar configuración.' });
    }
    setLoading(false);
  };

  // Confirmar y aplicar cortes a costos del proyecto e inventario de stock
  const handleConfirmAndApply = async () => {
    if (!optimizationResult || optimizationResult.results.length === 0) return;

    if (!confirm('Al confirmar, se descontarán las placas del inventario de stock y se imputará su costo automáticamente a los materiales del proyecto. ¿Desea proceder?')) return;

    setLoading(true);
    setMessage(null);

    // Mapear placas utilizadas para descontar de inventario y agregar a materiales
    const sheetsUsedMap: Array<{
      materialName: string;
      materialCategoryId: string;
      quantityUsed: number;
      unitPrice: number;
      inventoryMaterialId?: string | null;
    }> = [];

    // Categoría melamina/MDF por defecto
    const defaultCategory = materialCategories.find(c => c.name === 'Melamina' || c.name === 'MDF') || materialCategories[0];

    optimizationResult.results.forEach(res => {
      // Buscar la configuración de la placa original en sheets
      // res.sheetIndex es 1-indexed, flatSheets se mapeó desde sheets
      // Recuperar el material name buscando coincidencia en el array original sheets
      const originalSheet = sheets.find(s => s.length === res.sheetLength && s.width === res.sheetWidth && s.cost === res.cost);
      const matName = originalSheet?.material || 'Placa Melamina';

      // Intentar extraer el ID del inventario si está guardado en notes
      let invId: string | null = null;
      if (originalSheet?.notes && originalSheet.notes.includes('Id:')) {
        const match = originalSheet.notes.match(/Id:\s*([a-fA-F0-9\-]+)/);
        if (match) invId = match[1];
      }

      // Agrupar cantidades para pasarlo consolidado
      const existing = sheetsUsedMap.find(s => s.materialName === matName && s.unitPrice === res.cost);
      if (existing) {
        existing.quantityUsed += 1;
      } else {
        sheetsUsedMap.push({
          materialName: matName,
          materialCategoryId: defaultCategory?.id || '',
          quantityUsed: 1,
          unitPrice: res.cost,
          inventoryMaterialId: invId
        });
      }
    });

    const resCuts = await confirmCutlistCuts(projectId, sheetsUsedMap);

    if (resCuts.success) {
      // Guardar también la optimización
      await saveCutlist({
        projectId,
        kerf,
        edgeTrim,
        useGrain,
        parts,
        sheets,
        results: optimizationResult
      });

      setIsConfirmed(true);
      setMessage({ type: 'success', text: 'Corte confirmado. Placas imputadas a costos de materiales del proyecto y descontadas de stock.' });
      if (onConfirmSuccess) onConfirmSuccess();
    } else {
      setMessage({ type: 'error', text: resCuts.error || 'Error al aplicar cortes a inventario.' });
    }
    setLoading(false);
  };

  // Exportar piezas a CSV
  const handleExportCSV = () => {
    let csvContent = 'data:text/csv;charset=utf-8,Etiqueta,Largo,Ancho,Cantidad,Material,Espesor,Notas\n';
    parts.forEach(p => {
      csvContent += `"${p.label}",${p.length},${p.width},${p.qty},"${p.material}",${p.thickness},"${p.notes || ''}"\n`;
    });
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement('a');
    link.setAttribute('href', encodedUri);
    link.setAttribute('download', `piezas_corte_${projectNumber}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Importar CSV
  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const text = evt.target?.result as string;
      const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);

      // Saltar cabecera
      const newParts: Part[] = [];
      for (let i = 1; i < lines.length; i++) {
        const cols = lines[i].split(',').map(c => c.replace(/"/g, '').trim());
        if (cols.length >= 4) {
          newParts.push({
            label: cols[0],
            length: parseInt(cols[1]) || 500,
            width: parseInt(cols[2]) || 300,
            qty: parseInt(cols[3]) || 1,
            material: cols[4] || sheets[0]?.material || 'Melamina Blanca',
            thickness: parseInt(cols[5]) || 18,
            notes: cols[6] || ''
          });
        }
      }
      if (newParts.length > 0) {
        setParts(newParts);
        setMessage({ type: 'success', text: `Importadas ${newParts.length} piezas con éxito.` });
      } else {
        setMessage({ type: 'error', text: 'El archivo CSV no tiene el formato correcto.' });
      }
    };
    reader.readAsText(file);
  };

  return (
    <div style={{ display: 'grid', gridTemplateColumns: '1.2fr 1.8fr', gap: '20px', alignItems: 'stretch' }}>

      {/* Left panel: Config and lists */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

        {/* Action buttons */}
        <div className="card" style={{ padding: '16px', display: 'flex', flexWrap: 'wrap', gap: '10px', justifyContent: 'space-between' }}>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button className="btn btn-primary btn-sm" onClick={handleOptimize} disabled={loading}>
              <Play size={14} />
              <span>Optimizar</span>
            </button>
            <button className="btn btn-secondary btn-sm" onClick={handleSaveCutlist} disabled={loading}>
              <Save size={14} />
              <span>Guardar Config</span>
            </button>
          </div>
          {optimizationResult && (
            <button 
              className={`btn btn-sm ${isConfirmed ? 'btn-secondary' : 'btn-primary'}`} 
              style={{ backgroundColor: isConfirmed ? 'var(--success-light)' : 'var(--primary-color)', color: isConfirmed ? 'var(--success-color)' : '#ffffff', borderColor: isConfirmed ? 'var(--success-color)' : 'transparent' }}
              onClick={handleConfirmAndApply} 
              disabled={loading || isConfirmed}
            >
              {isConfirmed ? <CheckCircle size={14} /> : <Scissors size={14} />}
              <span>{isConfirmed ? 'Corte Aplicado' : 'Confirmar e Imputar'}</span>
            </button>
          )}
        </div>

        {message && (
          <div style={{ 
            backgroundColor: message.type === 'success' ? 'var(--success-light)' : 'var(--error-light)', 
            color: message.type === 'success' ? 'var(--success-color)' : 'var(--error-color)', 
            padding: '12px', 
            borderRadius: 'var(--radius-sm)', 
            fontSize: '0.85rem',
            border: `1px solid ${message.type === 'success' ? 'var(--success-color)' : 'var(--error-color)'}`
          }}>
            {message.text}
          </div>
        )}

        {/* Options */}
        <div className="card">
          <h3>Opciones de Cálculo</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginTop: '15px' }}>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label>Grosor de sierra (Kerf mm)</label>
              <input
                type="number"
                className="form-control"
                value={kerf}
                onChange={(e) => setKerf(Number(e.target.value))}
                min="0"
                max="10"
              />
            </div>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label>Refilado de bordes (mm)</label>
              <input
                type="number"
                className="form-control"
                value={edgeTrim}
                onChange={(e) => setEdgeTrim(Number(e.target.value))}
                min="0"
                max="50"
              />
            </div>
          </div>
          <div style={{ marginTop: '15px' }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
              <input
                type="checkbox"
                checked={useGrain}
                onChange={(e) => setUseGrain(e.target.checked)}
                style={{ width: '18px', height: '18px' }}
              />
              <span style={{ fontSize: '0.85rem', fontWeight: 500, color: 'var(--text-secondary)' }}>Respetar dirección del grano / veta</span>
            </label>
          </div>
        </div>

        {/* Placas Disponibles */}
        <div className="card">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
            <h3>1. Hojas / Placas Disponibles</h3>
            <button className="btn btn-secondary btn-sm" onClick={handleAddSheet} style={{ padding: '4px 8px' }}>
              <Plus size={14} />
            </button>
          </div>

          {/* Cargar desde stock dropdown */}
          <div style={{ marginBottom: '15px', padding: '10px', backgroundColor: 'var(--surface-hover)', borderRadius: 'var(--radius-sm)', border: '1px solid var(--border-color)' }}>
            <label style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block', marginBottom: '4px' }}>Cargar placa desde stock</label>
            <select
              className="form-control"
              style={{ fontSize: '0.8rem', padding: '6px' }}
              onChange={(e) => {
                const item = inventory.find(i => i.id === e.target.value);
                if (item) handleLoadSheetFromInventory(item);
                e.target.value = '';
              }}
              defaultValue=""
            >
              <option value="" disabled>-- Seleccionar madera de stock --</option>
              {inventory
                .filter(i => i.currentStock > 0 && (i.materialCategory.name.toLowerCase().includes('melamina') || i.materialCategory.name.toLowerCase().includes('mdf') || i.unit === 'placa'))
                .map(i => (
                  <option key={i.id} value={i.id}>{i.name} (Stock: {i.currentStock})</option>
                ))}
            </select>
          </div>

          <div style={{ maxHeight: '180px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {sheets.map((sheet, idx) => (
              <div key={idx} style={{ display: 'grid', gridTemplateColumns: '1.2fr 0.8fr 0.8fr 0.8fr 0.8fr 0.3fr', gap: '8px', alignItems: 'center', paddingBottom: '8px', borderBottom: '1px solid var(--border-color)' }}>
                <input
                  type="text"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Material"
                  value={sheet.material}
                  onChange={(e) => handleUpdateSheet(idx, 'material', e.target.value)}
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Largo mm"
                  value={sheet.length}
                  onChange={(e) => handleUpdateSheet(idx, 'length', Number(e.target.value))}
                  title="Longitud"
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Ancho mm"
                  value={sheet.width}
                  onChange={(e) => handleUpdateSheet(idx, 'width', Number(e.target.value))}
                  title="Ancho"
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Cant"
                  value={sheet.qty}
                  onChange={(e) => handleUpdateSheet(idx, 'qty', Number(e.target.value))}
                  title="Cantidad"
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Costo"
                  value={sheet.cost}
                  onChange={(e) => handleUpdateSheet(idx, 'cost', Number(e.target.value))}
                  title="Costo por placa"
                />
                <button 
                  type="button" 
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--error-color)' }}
                  onClick={() => handleRemoveSheet(idx)}
                >
                  <Trash2 size={14} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Piezas a Cortar */}
        <div className="card">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
            <h3>2. Piezas a Cortar</h3>
            <div style={{ display: 'flex', gap: '8px' }}>
              {/* Import CSV */}
              <label className="btn btn-secondary btn-sm" style={{ padding: '4px 8px', cursor: 'pointer' }}>
                <Upload size={14} />
                <input type="file" accept=".csv" style={{ display: 'none' }} onChange={handleImportCSV} />
              </label>
              <button className="btn btn-secondary btn-sm" onClick={handleExportCSV} title="Exportar Piezas CSV" style={{ padding: '4px 8px' }}>
                <Download size={14} />
              </button>
              <button className="btn btn-secondary btn-sm" onClick={handleAddPart} style={{ padding: '4px 8px' }}>
                <Plus size={14} />
              </button>
            </div>
          </div>

          <div style={{ maxHeight: '240px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {parts.map((part, idx) => (
              <div key={idx} style={{ display: 'grid', gridTemplateColumns: '1.2fr 0.8fr 0.8fr 0.6fr 1fr 0.3fr', gap: '8px', alignItems: 'center', paddingBottom: '8px', borderBottom: '1px solid var(--border-color)' }}>
                <input
                  type="text"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Etiqueta"
                  value={part.label}
                  onChange={(e) => handleUpdatePart(idx, 'label', e.target.value)}
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Largo"
                  value={part.length}
                  onChange={(e) => handleUpdatePart(idx, 'length', Number(e.target.value))}
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Ancho"
                  value={part.width}
                  onChange={(e) => handleUpdatePart(idx, 'width', Number(e.target.value))}
                />
                <input
                  type="number"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Cant"
                  value={part.qty}
                  onChange={(e) => handleUpdatePart(idx, 'qty', Number(e.target.value))}
                />
                <input
                  type="text"
                  className="form-control"
                  style={{ fontSize: '0.8rem', padding: '6px' }}
                  placeholder="Notas (ej: Veta)"
                  value={part.notes || ''}
                  onChange={(e) => handleUpdatePart(idx, 'notes', e.target.value)}
                />
                <button 
                  type="button" 
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--error-color)' }}
                  onClick={() => handleRemovePart(idx)}
                >
                  <Trash2 size={14} />
                </button>
              </div>
            ))}
          </div>
        </div>

      </div>

      {/* Right panel: SVG visual layout and yield results */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

        {/* Yield Results Summary */}
        {optimizationResult && (
          <div className="card" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))', gap: '15px', padding: '16px' }}>
            <div style={{ padding: '8px', borderRight: '1px solid var(--border-color)', textAlign: 'center' }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Aprovechamiento</span>
              <span style={{ fontSize: '1.4rem', fontWeight: 800, color: 'var(--success-color)' }}>
                {optimizationResult.totals.utilizationPercentage}%
              </span>
            </div>
            <div style={{ padding: '8px', borderRight: '1px solid var(--border-color)', textAlign: 'center' }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Placas Usadas</span>
              <span style={{ fontSize: '1.4rem', fontWeight: 800 }}>
                {optimizationResult.totals.sheetsUsedCount}
              </span>
            </div>
            <div style={{ padding: '8px', borderRight: '1px solid var(--border-color)', textAlign: 'center' }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Costo Placas</span>
              <span style={{ fontSize: '1.3rem', fontWeight: 700 }}>
                {formatARS(optimizationResult.totals.totalSheetsCost)}
              </span>
            </div>
            <div style={{ padding: '8px', textAlign: 'center' }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Pérdida ($)</span>
              <span style={{ fontSize: '1.3rem', fontWeight: 700, color: 'var(--error-color)' }}>
                {formatARS(optimizationResult.totals.wastedCost)}
              </span>
            </div>
          </div>
        )}

        {/* Visual Render Container */}
        <div className="card" style={{ flexGrow: 1, display: 'flex', flexDirection: 'column', minHeight: '500px' }}>
          <div className="card-header" style={{ marginBottom: '10px' }}>
            <h3>Plano de Cortes</h3>
            {optimizationResult && (
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Zoom:</span>
                <input
                  type="range"
                  min="0.05"
                  max="0.6"
                  step="0.02"
                  value={zoomScale}
                  onChange={(e) => setZoomScale(parseFloat(e.target.value))}
                  style={{ width: '80px', cursor: 'pointer' }}
                />
                <span style={{ fontSize: '0.8rem', fontWeight: 500 }}>{Math.round(zoomScale * 100 * 5)}%</span>
              </div>
            )}
          </div>

          <div style={{ 
            flexGrow: 1, 
            backgroundColor: 'var(--bg-color)', 
            border: '1px dashed var(--border-color)', 
            borderRadius: 'var(--radius-sm)', 
            overflow: 'auto', 
            padding: '20px', 
            display: 'flex', 
            flexDirection: 'column', 
            gap: '30px',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            {!optimizationResult ? (
              <div style={{ textAlign: 'center', color: 'var(--text-muted)' }}>
                <Scissors size={40} style={{ marginBottom: '10px', display: 'inline-block' }} />
                <p>Cargue piezas y placas, y presione el botón <strong>Optimizar</strong> para generar el diagrama de cortes.</p>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '40px', width: '100%', alignItems: 'center' }}>
                {optimizationResult.results.map((res, sheetIdx) => {
                  const svgW = res.sheetWidth * zoomScale;
                  const svgH = res.sheetLength * zoomScale;
                  return (
                    <div key={sheetIdx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
                      <div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--text-secondary)' }}>
                        Placa #{res.sheetIndex} ({res.sheetWidth} x {res.sheetLength} mm) - Rendimiento: {res.utilizationPercentage}%
                      </div>

                      <div style={{
                        boxShadow: 'var(--shadow-md)',
                        border: '2px solid #78350f', // Wood border
                        backgroundColor: '#1c1917', // Dark wood background
                        display: 'inline-block',
                      }}>
                        <svg width={svgW} height={svgH} style={{ display: 'block' }}>
                          {/* Fondo de refilado / descarte inicial */}
                          <rect 
                            x={0} 
                            y={0} 
                            width={res.sheetWidth * zoomScale} 
                            height={res.sheetLength * zoomScale} 
                            fill="rgba(239, 68, 68, 0.08)"
                          />

                          {/* Área útil de placa */}
                          <rect
                            x={edgeTrim * zoomScale}
                            y={edgeTrim * zoomScale}
                            width={(res.sheetWidth - edgeTrim * 2) * zoomScale}
                            height={(res.sheetLength - edgeTrim * 2) * zoomScale}
                            fill="#292524" // Dark grey surface
                            stroke="rgba(255, 255, 255, 0.1)"
                            strokeWidth={1}
                          />

                          {/* Piezas colocadas */}
                          {res.placedParts.map((part, pIdx) => {
                            const px = part.x * zoomScale;
                            const py = part.y * zoomScale;
                            const pw = part.w * zoomScale;
                            const ph = part.h * zoomScale;

                            // Color de pieza premium (acento amber-wood)
                            return (
                              <g key={pIdx}>
                                <rect
                                  x={px}
                                  y={py}
                                  width={pw}
                                  height={ph}
                                  fill="#f59e0b" // Amber/Gold piece
                                  stroke="#78350f" // Brown border
                                  strokeWidth={1}
                                  title={`${part.label}: ${part.h}x${part.w}`}
                                />
                                {/* Etiqueta */}
                                {pw > 30 && ph > 20 && (
                                  <text
                                    x={px + pw / 2}
                                    y={py + ph / 2}
                                    fontSize={Math.max(9, 14 * zoomScale)}
                                    fontWeight="600"
                                    fill="#451a03"
                                    textAnchor="middle"
                                    dominantBaseline="middle"
                                  >
                                    {part.label}
                                  </text>
                                )}
                                {/* Medida */}
                                {pw > 40 && ph > 35 && (
                                  <text
                                    x={px + pw / 2}
                                    y={py + ph / 2 + 10}
                                    fontSize={Math.max(8, 11 * zoomScale)}
                                    fill="#78350f"
                                    textAnchor="middle"
                                    dominantBaseline="middle"
                                  >
                                    {Math.round(part.h)}x{Math.round(part.w)}
                                  </text>
                                )}
                              </g>
                            );
                          })}

                          {/* Renderizar espacios libres de desperdicio */}
                          {res.freeSpaces.map((space, sIdx) => {
                            const sx = space.x * zoomScale;
                            const sy = space.y * zoomScale;
                            const sw = space.w * zoomScale;
                            const sh = space.h * zoomScale;

                            if (sw > 3 && sh > 3) {
                              return (
                                <g key={`free-${sIdx}`}>
                                  {/* Patrón rayado para descarte */}
                                  <rect
                                    x={sx}
                                    y={sy}
                                    width={sw}
                                    height={sh}
                                    fill="rgba(255,255,255,0.05)"
                                    stroke="rgba(255, 255, 255, 0.15)"
                                    strokeDasharray="2,2"
                                  />
                                  {sw > 30 && sh > 20 && (
                                    <text
                                      x={sx + sw / 2}
                                      y={sy + sh / 2}
                                      fontSize={9}
                                      fill="rgba(255,255,255,0.3)"
                                      textAnchor="middle"
                                      dominantBaseline="middle"
                                    >
                                      Sobrante
                                    </text>
                                  )}
                                </g>
                              );
                            }
                            return null;
                          })}
                        </svg>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* Unplaced pieces warning */}
          {optimizationResult && optimizationResult.unplacedParts.length > 0 && (
            <div style={{ 
              marginTop: '15px', 
              backgroundColor: 'var(--error-light)', 
              color: 'var(--error-color)', 
              padding: '12px', 
              borderRadius: 'var(--radius-sm)', 
              fontSize: '0.85rem',
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
              border: '1px solid var(--error-color)'
            }}>
              <AlertTriangle size={20} />
              <div>
                <strong>Atención:</strong> Las siguientes piezas no cupieron en las placas cargadas:
                <ul style={{ paddingLeft: '20px', marginTop: '4px' }}>
                  {optimizationResult.unplacedParts.map((p, idx) => (
                    <li key={idx}>{p.label} ({p.h}x{p.w}mm) x {p.qty} unidad(es)</li>
                  ))}
                </ul>
              </div>
            </div>
          )}

        </div>

      </div>

    </div>
  );
}

'use client';

import React, { useState, useMemo } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { 
  ArrowLeft,
  Calendar,
  DollarSign,
  TrendingUp,
  FolderKanban,
  Edit2,
  Trash2,
  Briefcase,
  Users,
  Settings,
  AlertTriangle,
  Scissors,
  CheckCircle,
  Clock,
  Plus,
  Coins,
  FileText
} from 'lucide-react';
import { 
  updateProject, 
  deleteProject,
  addProjectMaterial, 
  deleteProjectMaterial,
  addProjectLabor,
  deleteProjectLabor,
  addProjectEmployeeWork,
  deleteProjectEmployeeWork,
  addProjectExpense,
  deleteProjectExpense,
  addProjectPayment,
  deleteProjectPayment
} from '../actions';
import CutlistOptimizer from '@/components/CutlistOptimizer';

interface ProjectDetailManagerProps {
  project: any;
  clients: any[];
  furnitureTypes: any[];
  employees: any[];
  materialCategories: any[];
  expenseCategories: any[];
  paymentMethods: any[];
  inventory: any[];
  suppliers: any[];
}

export default function ProjectDetailManager({
  project: initialProject,
  clients,
  furnitureTypes,
  employees,
  materialCategories,
  expenseCategories,
  paymentMethods,
  inventory,
  suppliers
}: ProjectDetailManagerProps) {
  const router = useRouter();
  const [project, setProject] = useState(initialProject);
  const [activeTab, setActiveTab] = useState<'detalles' | 'costos' | 'pagos' | 'comparativa' | 'cutlist'>('detalles');
  const [costsTab, setCostsTab] = useState<'materiales' | 'labor' | 'empleados' | 'gastos_directos'>('materiales');

  // Basic edit form states
  const [clientId, setClientId] = useState(project.clientId);
  const [furnitureTypeId, setFurnitureTypeId] = useState(project.furnitureTypeId);
  const [description, setDescription] = useState(project.description);
  const [priority, setPriority] = useState(project.priority);
  const [status, setStatus] = useState(project.status);
  const [agreedPrice, setAgreedPrice] = useState(project.agreedPrice);
  const [startDateInput, setStartDateInput] = useState(project.startDate ? new Date(project.startDate).toISOString().substring(0, 10) : '');
  const [deliveryDateInput, setDeliveryDateInput] = useState(project.estimatedDeliveryDate ? new Date(project.estimatedDeliveryDate).toISOString().substring(0, 10) : '');
  const [actualDeliveryDateInput, setActualDeliveryDateInput] = useState(project.actualDeliveryDate ? new Date(project.actualDeliveryDate).toISOString().substring(0, 10) : '');
  const [estimatedBudget, setEstimatedBudget] = useState(project.estimatedBudget || 0);
  const [estimatedLaborCost, setEstimatedLaborCost] = useState(project.estimatedLaborCost || 0);
  const [estimatedLaborDays, setEstimatedLaborDays] = useState(project.estimatedLaborDays || 0);
  const [estimatedOtherExpenses, setEstimatedOtherExpenses] = useState(project.estimatedOtherExpenses || 0);
  const [workOrderNotes, setWorkOrderNotes] = useState(project.workOrderNotes || '');

  // Form add cost states
  const [matMode, setMatMode] = useState<'manual' | 'stock'>('manual');
  const [matName, setMatName] = useState('');
  const [matCategoryId, setMatCategoryId] = useState(materialCategories[0]?.id || '');
  const [matQty, setMatQty] = useState(1);
  const [matUnit, setMatUnit] = useState('placa');
  const [matPrice, setMatPrice] = useState(0);
  const [matInventoryId, setMatInventoryId] = useState('');
  const [matSupplierId, setMatSupplierId] = useState('');

  const [labDesc, setLabDesc] = useState('');
  const [labHoursDays, setLabHoursDays] = useState(1);
  const [labRate, setLabRate] = useState(0);

  const [empId, setEmpId] = useState(employees[0]?.id || '');
  const [empDate, setEmpDate] = useState(new Date().toISOString().substring(0, 10));
  const [empDays, setEmpDays] = useState(1);
  const [empRate, setEmpRate] = useState(employees[0]?.ratePerDay || 0);
  const [empNotes, setEmpNotes] = useState('');

  const [expCategoryId, setExpCategoryId] = useState(expenseCategories[0]?.id || '');
  const [expDesc, setExpDesc] = useState('');
  const [expAmount, setExpAmount] = useState(0);
  const [expSupplierId, setExpSupplierId] = useState('');

  const [payDate, setPayDate] = useState(new Date().toISOString().substring(0, 10));
  const [payAmount, setPayAmount] = useState(0);
  const [payMethodId, setPayMethodId] = useState(paymentMethods[0]?.id || '');
  const [payNotes, setPayNotes] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  // ARS Currency formatter
  const formatARS = (val: number) => {
    return new Intl.NumberFormat('es-AR', {
      style: 'currency',
      currency: 'ARS',
      minimumFractionDigits: 0
    }).format(val);
  };

  // Re-fetch project detail to update client side state
  const refreshProjectData = async () => {
    const res = await fetch(`/api/projects/${project.id}`);
    if (res.ok) {
      const data = await res.json();
      setProject(data);
    } else {
      router.refresh();
    }
  };

  // 1. Submit basic details form
  const handleUpdateProjectBasic = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setLoading(true);

    const estProfit = agreedPrice - (estimatedLaborCost + estimatedOtherExpenses);

    const res = await updateProject(project.id, {
      clientId,
      furnitureTypeId,
      description,
      priority,
      status,
      agreedPrice: Number(agreedPrice),
      startDate: startDateInput ? new Date(startDateInput) : null,
      estimatedDeliveryDate: deliveryDateInput ? new Date(deliveryDateInput) : null,
      actualDeliveryDate: actualDeliveryDateInput ? new Date(actualDeliveryDateInput) : null,
      estimatedBudget: Number(estimatedBudget),
      estimatedLaborCost: Number(estimatedLaborCost),
      estimatedLaborDays: Number(estimatedLaborDays),
      estimatedOtherExpenses: Number(estimatedOtherExpenses),
      estimatedProfit: estProfit > 0 ? estProfit : 0,
      workOrderNotes: workOrderNotes || null,
    });

    if (res.success && res.project) {
      setSuccessMsg('Información de proyecto actualizada con éxito.');
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al actualizar proyecto.');
    }
    setLoading(false);
  };

  // Delete project
  const handleDeleteProject = async () => {
    if (!confirm('¿Está seguro de que desea eliminar este proyecto? Esta acción es irreversible.')) return;
    setLoading(true);
    const res = await deleteProject(project.id);
    if (res.success) {
      router.push('/proyectos');
    } else {
      alert(res.error || 'Error al eliminar proyecto.');
    }
    setLoading(false);
  };

  // 2. Add Project Material
  const handleAddMaterial = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    let res;
    if (matMode === 'stock') {
      const invItem = inventory.find(i => i.id === matInventoryId);
      if (!invItem) {
        setError('Debe seleccionar un item de stock válido.');
        setLoading(false);
        return;
      }
      res = await addProjectMaterial({
        projectId: project.id,
        materialName: invItem.name,
        materialCategoryId: invItem.materialCategoryId,
        quantity: Number(matQty),
        unit: invItem.unit,
        unitPrice: Number(matPrice),
        inventoryMaterialId: matInventoryId,
      });
    } else {
      res = await addProjectMaterial({
        projectId: project.id,
        materialName: matName,
        materialCategoryId: matCategoryId,
        quantity: Number(matQty),
        unit: matUnit,
        unitPrice: Number(matPrice),
        supplierId: matSupplierId || null,
      });
    }

    if (res.success) {
      setMatName('');
      setMatQty(1);
      setMatPrice(0);
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al agregar material');
    }
    setLoading(false);
  };

  const handleDeleteMaterial = async (id: string) => {
    if (!confirm('¿Desea eliminar este material? Si provenía de stock, la cantidad se devolverá al inventario.')) return;
    const res = await deleteProjectMaterial(id);
    if (res.success) {
      await refreshProjectData();
    } else {
      alert(res.error || 'Error al eliminar');
    }
  };

  // 3. Add General Labor
  const handleAddLabor = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const res = await addProjectLabor({
      projectId: project.id,
      description: labDesc,
      hoursOrDays: Number(labHoursDays),
      rate: Number(labRate)
    });
    if (res.success) {
      setLabDesc('');
      setLabHoursDays(1);
      setLabRate(0);
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al agregar mano de obra');
    }
    setLoading(false);
  };

  const handleDeleteLabor = async (id: string) => {
    if (!confirm('¿Desea eliminar este registro de mano de obra?')) return;
    const res = await deleteProjectLabor(id);
    if (res.success) await refreshProjectData();
  };

  // 4. Add Employee Work Record
  const handleAddEmployeeWork = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const res = await addProjectEmployeeWork({
      projectId: project.id,
      employeeId: empId,
      date: new Date(empDate),
      daysWorked: Number(empDays),
      ratePerDay: Number(empRate),
      notes: empNotes || null
    });
    if (res.success) {
      setEmpDays(1);
      setEmpNotes('');
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al registrar jornal');
    }
    setLoading(false);
  };

  const handleDeleteEmployeeWork = async (id: string) => {
    if (!confirm('¿Desea eliminar esta jornada de empleado?')) return;
    const res = await deleteProjectEmployeeWork(id);
    if (res.success) await refreshProjectData();
  };

  // 5. Add Project Expense
  const handleAddExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const res = await addProjectExpense({
      projectId: project.id,
      expenseCategoryId: expCategoryId,
      description: expDesc,
      amount: Number(expAmount),
      supplierId: expSupplierId || null
    });
    if (res.success) {
      setExpDesc('');
      setExpAmount(0);
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al registrar gasto');
    }
    setLoading(false);
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm('¿Desea eliminar este gasto directo?')) return;
    const res = await deleteProjectExpense(id);
    if (res.success) await refreshProjectData();
  };

  // 6. Add Payment
  const handleAddPayment = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const res = await addProjectPayment({
      projectId: project.id,
      date: new Date(payDate),
      amount: Number(payAmount),
      paymentMethodId: payMethodId,
      notes: payNotes || null
    });
    if (res.success) {
      setPayAmount(0);
      setPayNotes('');
      await refreshProjectData();
    } else {
      setError(res.error || 'Error al registrar cobro');
    }
    setLoading(false);
  };

  const handleDeletePayment = async (id: string) => {
    if (!confirm('¿Desea eliminar este registro de cobro?')) return;
    const res = await deleteProjectPayment(id);
    if (res.success) await refreshProjectData();
  };

  // Financial calculations
  const finances = useMemo(() => {
    const materials = project.materials.reduce((acc: number, m: any) => acc + m.totalPrice, 0);
    const labor = project.labor.reduce((acc: number, l: any) => acc + l.total, 0);
    const employeeLabor = project.employees.reduce((acc: number, e: any) => acc + e.total, 0);
    const expenses = project.expenses.reduce((acc: number, e: any) => acc + e.amount, 0);

    const totalCost = materials + labor + employeeLabor + expenses;
    const totalPaid = project.payments.reduce((acc: number, p: any) => acc + p.amount, 0);
    const balanceOwed = project.agreedPrice - totalPaid;

    const grossProfit = project.agreedPrice - totalCost;
    const netProfit = totalPaid - totalCost;
    const margin = project.agreedPrice > 0 ? (grossProfit / project.agreedPrice) * 100 : 0;

    return {
      materials,
      labor: labor + employeeLabor,
      expenses,
      totalCost,
      totalPaid,
      balanceOwed,
      grossProfit,
      netProfit,
      margin: parseFloat(margin.toFixed(1))
    };
  }, [project]);

  // Comparison Budget vs Real
  const comparison = useMemo(() => {
    const estLabor = project.estimatedLaborCost || 0;
    const estExpenses = project.estimatedOtherExpenses || 0;
    const estProfit = project.estimatedProfit || 0;
    const estBudget = project.estimatedBudget || project.agreedPrice;

    // Supongamos que el presupuesto de materiales estimado es la diferencia
    const estMaterials = estBudget - (estLabor + estExpenses + estProfit);
    const realMaterials = finances.materials;
    const realLabor = finances.labor;
    const realExpenses = finances.expenses;
    const realCost = finances.totalCost;
    const realProfit = finances.grossProfit; // Ganancia real en base a lo acordado

    const budgetDiff = realCost - estBudget;
    const budgetDiffPct = estBudget > 0 ? (budgetDiff / estBudget) * 100 : 0;

    return {
      estBudget,
      estMaterials: estMaterials > 0 ? estMaterials : 0,
      realMaterials,
      estLabor,
      realLabor,
      estExpenses,
      realExpenses,
      estProfit,
      realProfit,
      budgetDiff,
      budgetDiffPct: parseFloat(budgetDiffPct.toFixed(1))
    };
  }, [project, finances]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

      {/* Top Banner Navigation */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Link href="/proyectos" style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', color: 'var(--primary-color)', fontWeight: 600 }}>
          <ArrowLeft size={16} />
          <span>Volver a Proyectos</span>
        </Link>
        <span style={{ fontWeight: 800, fontSize: '1.25rem', color: 'var(--text-muted)' }}>
          {project.projectNumber}
        </span>
      </div>

      {/* Project title and brief summary cards */}
      <div className="card" style={{ padding: '20px', display: 'flex', flexWrap: 'wrap', gap: '30px', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <span className="badge badge-primary" style={{ fontSize: '0.7rem', padding: '2px 8px', marginBottom: '6px' }}>{project.furnitureType.name}</span>
          <h2 style={{ fontSize: '1.4rem', fontWeight: 700, margin: '2px 0 6px 0' }}>{project.client.name}</h2>
          <p style={{ fontSize: '0.85rem' }}>{project.description}</p>
        </div>

        {/* Economic Summary Banner */}
        <div style={{ display: 'flex', gap: '25px', flexWrap: 'wrap' }}>
          <div style={{ textAlign: 'center' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Acordado</span>
            <span style={{ fontSize: '1.15rem', fontWeight: 700 }}>{formatARS(project.agreedPrice)}</span>
          </div>
          <div style={{ textAlign: 'center' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Costo Acumulado</span>
            <span style={{ fontSize: '1.15rem', fontWeight: 700, color: 'var(--error-color)' }}>{formatARS(finances.totalCost)}</span>
          </div>
          <div style={{ textAlign: 'center' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Cobrado</span>
            <span style={{ fontSize: '1.15rem', fontWeight: 700, color: 'var(--success-color)' }}>{formatARS(finances.totalPaid)}</span>
          </div>
          <div style={{ textAlign: 'center' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block' }}>Saldo</span>
            <span style={{ fontSize: '1.15rem', fontWeight: 700, color: finances.balanceOwed > 0 ? 'var(--warning-color)' : 'var(--success-color)' }}>
              {formatARS(finances.balanceOwed)}
            </span>
          </div>
        </div>
      </div>

      {/* Tabs Menu */}
      <div className="tabs">
        <button className={`tab-btn ${activeTab === 'detalles' ? 'active' : ''}`} onClick={() => setActiveTab('detalles')}>
          <Settings size={15} style={{ verticalAlign: 'middle', marginRight: '5px' }} />
          Detalles de Obra
        </button>
        <button className={`tab-btn ${activeTab === 'costos' ? 'active' : ''}`} onClick={() => setActiveTab('costos')}>
          <Coins size={15} style={{ verticalAlign: 'middle', marginRight: '5px' }} />
          Cargar Costos
        </button>
        <button className={`tab-btn ${activeTab === 'pagos' ? 'active' : ''}`} onClick={() => setActiveTab('pagos')}>
          <DollarSign size={15} style={{ verticalAlign: 'middle', marginRight: '5px' }} />
          Cobros de Cliente
        </button>
        <button className={`tab-btn ${activeTab === 'comparativa' ? 'active' : ''}`} onClick={() => setActiveTab('comparativa')}>
          <TrendingUp size={15} style={{ verticalAlign: 'middle', marginRight: '5px' }} />
          Presupuesto vs Costo Real
        </button>
        <button className={`tab-btn ${activeTab === 'cutlist' ? 'active' : ''}`} onClick={() => setActiveTab('cutlist')}>
          <Scissors size={15} style={{ verticalAlign: 'middle', marginRight: '5px' }} />
          Optimizador de Cortes
        </button>
      </div>

      {/* ERROR / SUCCESS ALERTS */}
      {error && <div style={{ backgroundColor: 'var(--error-light)', color: 'var(--error-color)', padding: '12px', borderRadius: 'var(--radius-sm)', border: '1px solid var(--error-color)' }}>{error}</div>}
      {successMsg && <div style={{ backgroundColor: 'var(--success-light)', color: 'var(--success-color)', padding: '12px', borderRadius: 'var(--radius-sm)', border: '1px solid var(--success-color)' }}>{successMsg}</div>}

      {/* TAB 1: DETALLES GENERALES (EDITAR PROYECTO) */}
      {activeTab === 'detalles' && (
        <div className="card">
          <form onSubmit={handleUpdateProjectBasic} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h3>Modificar Atributos del Proyecto</h3>
              <button type="button" className="btn btn-danger btn-sm" onClick={handleDeleteProject} disabled={loading}>
                <Trash2 size={14} /> Eliminar Proyecto
              </button>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Cliente</label>
                <select className="form-control" value={clientId} onChange={(e) => setClientId(e.target.value)} required>
                  {clients.map(c => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
              </div>
              <div className="form-group">
                <label>Tipo de Mueble</label>
                <select className="form-control" value={furnitureTypeId} onChange={(e) => setFurnitureTypeId(e.target.value)} required>
                  {furnitureTypes.map(t => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="form-group">
              <label>Descripción del Trabajo</label>
              <input type="text" className="form-control" value={description} onChange={(e) => setDescription(e.target.value)} required />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Prioridad</label>
                <select className="form-control" value={priority} onChange={(e) => setPriority(e.target.value)} required>
                  <option value="baja">Baja</option>
                  <option value="media">Media</option>
                  <option value="alta">Alta</option>
                </select>
              </div>
              <div className="form-group">
                <label>Estado de Obra</label>
                <select className="form-control" value={status} onChange={(e) => setStatus(e.target.value)} required>
                  <option value="presupuesto">Presupuesto</option>
                  <option value="a_confirmar">A Confirmar</option>
                  <option value="confirmado">Confirmado</option>
                  <option value="en_proceso">En Proceso</option>
                  <option value="finalizado">Finalizado</option>
                  <option value="entregado">Entregado</option>
                  <option value="cancelado">Cancelado</option>
                </select>
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Fecha de Inicio</label>
                <input type="date" className="form-control" value={startDateInput} onChange={(e) => setStartDateInput(e.target.value)} />
              </div>
              <div className="form-group">
                <label>Fecha Estimada de Entrega</label>
                <input type="date" className="form-control" value={deliveryDateInput} onChange={(e) => setDeliveryDateInput(e.target.value)} />
              </div>
              <div className="form-group">
                <label>Fecha Real de Entrega</label>
                <input type="date" className="form-control" value={actualDeliveryDateInput} onChange={(e) => setActualDeliveryDateInput(e.target.value)} />
              </div>
            </div>

            <div className="form-grid" style={{ borderTop: '1px solid var(--border-color)', paddingTop: '15px' }}>
              <div className="form-group">
                <label>Precio Acordado Final (ARS)</label>
                <input type="number" className="form-control" value={agreedPrice} onChange={(e) => setAgreedPrice(Number(e.target.value))} required />
              </div>
              <div className="form-group">
                <label>Presupuesto Estimado Global</label>
                <input type="number" className="form-control" value={estimatedBudget} onChange={(e) => setEstimatedBudget(Number(e.target.value))} />
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Costo de Mano de Obra Estimada (ARS)</label>
                <input type="number" className="form-control" value={estimatedLaborCost} onChange={(e) => setEstimatedLaborCost(Number(e.target.value))} />
              </div>
              <div className="form-group">
                <label>Días de Trabajo Estimados</label>
                <input type="number" className="form-control" value={estimatedLaborDays} onChange={(e) => setEstimatedLaborDays(Number(e.target.value))} />
              </div>
              <div className="form-group">
                <label>Gastos Varios Estimados (ARS)</label>
                <input type="number" className="form-control" value={estimatedOtherExpenses} onChange={(e) => setEstimatedOtherExpenses(Number(e.target.value))} />
              </div>
            </div>

            <div className="form-group">
              <label>Notas de Taller / Orden de Trabajo</label>
              <textarea className="form-control" style={{ minHeight: '80px' }} placeholder="Medidas críticas, colocación de bisagras, advertencias..." value={workOrderNotes} onChange={(e) => setWorkOrderNotes(e.target.value)} />
            </div>

            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button type="submit" className="btn btn-primary" disabled={loading}>
                {loading ? 'Guardando...' : 'Actualizar Proyecto'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* TAB 2: GESTION DE COSTOS */}
      {activeTab === 'costos' && (
        <div style={{ display: 'grid', gridTemplateColumns: '1.2fr 1.8fr', gap: '20px', alignItems: 'stretch' }}>

          {/* Form Side */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

            {/* Cost Selector menu */}
            <div className="card" style={{ padding: '16px' }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', display: 'block', marginBottom: '8px' }}>Categoría de Costo</span>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <button className={`btn btn-sm ${costsTab === 'materiales' ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setCostsTab('materiales')} style={{ justifyContent: 'flex-start' }}>Materiales</button>
                <button className={`btn btn-sm ${costsTab === 'labor' ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setCostsTab('labor')} style={{ justifyContent: 'flex-start' }}>Mano Obra General</button>
                <button className={`btn btn-sm ${costsTab === 'empleados' ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setCostsTab('empleados')} style={{ justifyContent: 'flex-start' }}>Operarios (Jornadas)</button>
                <button className={`btn btn-sm ${costsTab === 'gastos_directos' ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setCostsTab('gastos_directos')} style={{ justifyContent: 'flex-start' }}>Gastos Directos (Fletes/etc.)</button>
              </div>
            </div>

            {/* FORM 2.1: MATERIALES */}
            {costsTab === 'materiales' && (
              <div className="card">
                <h3>Cargar Material</h3>
                <div style={{ display: 'flex', gap: '10px', margin: '12px 0' }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', fontSize: '0.8rem' }}>
                    <input type="radio" checked={matMode === 'manual'} onChange={() => setMatMode('manual')} /> Compra Directa
                  </label>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', fontSize: '0.8rem' }}>
                    <input type="radio" checked={matMode === 'stock'} onChange={() => setMatMode('stock')} /> Consumir de Stock
                  </label>
                </div>

                <form onSubmit={handleAddMaterial} style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                  {matMode === 'stock' ? (
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Seleccionar Material en Stock</label>
                      <select 
                        className="form-control" 
                        value={matInventoryId} 
                        onChange={(e) => {
                          setMatInventoryId(e.target.value);
                          const item = inventory.find(i => i.id === e.target.value);
                          if (item) {
                            setMatPrice(item.unitCost);
                            setMatUnit(item.unit);
                          }
                        }}
                        required
                      >
                        <option value="" disabled>-- Buscar en stock --</option>
                        {inventory.filter(i => i.currentStock > 0).map(i => (
                          <option key={i.id} value={i.id}>{i.name} (Stock: {i.currentStock})</option>
                        ))}
                      </select>
                    </div>
                  ) : (
                    <>
                      <div className="form-group" style={{ marginBottom: 0 }}>
                        <label>Nombre del Material *</label>
                        <input type="text" className="form-control" placeholder="ej: Tornillos 3.5x16mm" value={matName} onChange={(e) => setMatName(e.target.value)} required />
                      </div>
                      <div className="form-grid">
                        <div className="form-group" style={{ marginBottom: 0 }}>
                          <label>Categoría *</label>
                          <select className="form-control" value={matCategoryId} onChange={(e) => setMatCategoryId(e.target.value)} required>
                            {materialCategories.map(c => (
                              <option key={c.id} value={c.id}>{c.name}</option>
                            ))}
                          </select>
                        </div>
                        <div className="form-group" style={{ marginBottom: 0 }}>
                          <label>Unidad *</label>
                          <input type="text" className="form-control" placeholder="u, m, placa, etc." value={matUnit} onChange={(e) => setMatUnit(e.target.value)} required />
                        </div>
                      </div>
                    </>
                  )}

                  <div className="form-grid">
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Cantidad *</label>
                      <input type="number" className="form-control" value={matQty} onChange={(e) => setMatQty(Number(e.target.value))} min="0.01" step="0.01" required />
                    </div>
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Costo Unitario (ARS) *</label>
                      <input type="number" className="form-control" value={matPrice} onChange={(e) => setMatPrice(Number(e.target.value))} min="0" required />
                    </div>
                  </div>

                  {matMode === 'manual' && (
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Proveedor (Opcional)</label>
                      <select className="form-control" value={matSupplierId} onChange={(e) => setMatSupplierId(e.target.value)}>
                        <option value="">-- Comprado a --</option>
                        {suppliers.map(s => (
                          <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                      </select>
                    </div>
                  )}

                  <button type="submit" className="btn btn-primary btn-sm" disabled={loading}>
                    Agregar Material
                  </button>
                </form>
              </div>
            )}

            {/* FORM 2.2: MANO OBRA GENERAL */}
            {costsTab === 'labor' && (
              <div className="card">
                <h3>Cargar Mano de Obra General</h3>
                <form onSubmit={handleAddLabor} style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label>Descripción de Tarea *</label>
                    <input type="text" className="form-control" placeholder="ej: Pintado laqueado especial" value={labDesc} onChange={(e) => setLabDesc(e.target.value)} required />
                  </div>
                  <div className="form-grid">
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Horas o Días Trabajados *</label>
                      <input type="number" className="form-control" value={labHoursDays} onChange={(e) => setLabHoursDays(Number(e.target.value))} min="0.01" step="0.01" required />
                    </div>
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Valor / Costo Unitario *</label>
                      <input type="number" className="form-control" value={labRate} onChange={(e) => setLabRate(Number(e.target.value))} min="0" required />
                    </div>
                  </div>
                  <button type="submit" className="btn btn-primary btn-sm" disabled={loading}>Agregar Mano de Obra</button>
                </form>
              </div>
            )}

            {/* FORM 2.3: OPERARIOS JORNADAS */}
            {costsTab === 'empleados' && (
              <div className="card">
                <h3>Registrar Jornal de Empleado</h3>
                <form onSubmit={handleAddEmployeeWork} style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label>Empleado *</label>
                    <select 
                      className="form-control" 
                      value={empId} 
                      onChange={(e) => {
                        setEmpId(e.target.value);
                        const emp = employees.find(emp => emp.id === e.target.value);
                        if (emp) setEmpRate(emp.ratePerDay);
                      }}
                      required
                    >
                      {employees.map(e => (
                        <option key={e.id} value={e.id}>{e.name} (Ref: {formatARS(e.ratePerDay)}/día)</option>
                      ))}
                    </select>
                  </div>
                  <div className="form-grid">
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Fecha Jornada *</label>
                      <input type="date" className="form-control" value={empDate} onChange={(e) => setEmpDate(e.target.value)} required />
                    </div>
                    <div className="form-group" style={{ marginBottom: 0 }}>
                      <label>Días Trabajados *</label>
                      <input type="number" className="form-control" value={empDays} onChange={(e) => setEmpDays(Number(e.target.value))} min="0.1" step="0.1" required />
                    </div>
                  </div>
                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label>Valor por Día acordado (ARS) *</label>
                    <input type="number" className="form-control" value={empRate} onChange={(e) => setEmpRate(Number(e.target.value))} min="0" required />
                  </div>
                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label>Tarea / Log de Productividad</label>
