25: async function updateProjectPaymentStatus(projectId: string, agreedPriceOverride?: number) {
26:   const project = await prisma.project.findUnique({
27:     where: { id: projectId },
28:     include: { payments: { where: { deletedAt: null } } }
29:   });
30: 
31:   if (!project) return;
32: 
