133: export async function recordStockTransaction(data: {
134:   inventoryId: string;
135:   type: 'entrada' | 'salida' | 'ajuste';
136:   quantity: number; // Para entrada/salida: el delta. Para ajuste: el nuevo stock absoluto.
137:   notes?: string | null;
138:   supplierId?: string | null;
139: }) {
140:   try {
141:     return await prisma.$transaction(async (tx) => {
142:       const item = await tx.inventory.findUnique({
143:         where: { id: data.inventoryId }
144:       });
145:       if (!item) throw new Error('Item de inventario no encontrado');
146: 
147:       let newStock = item.currentStock;
148:       let transactionQty = data.quantity;
149: 
150:       if (data.type === 'entrada') {
151:         newStock = item.currentStock + data.quantity;
152:       } else if (data.type === 'salida') {
153:         newStock = item.currentStock - data.quantity;
154:       } else if (data.type === 'ajuste') {
155:         newStock = data.quantity;
156:         transactionQty = data.quantity - item.currentStock; // La diferencia para el log
157:       }
158: 
159:       if (newStock < 0) {
160:         throw new Error('El stock no puede quedar en negativo.');
161:       }
162: 
163:       // 1. Crear transacción de inventario
164:       const transaction = await tx.inventoryTransaction.create({
165:         data: {
166:           inventoryId: data.inventoryId,
167:           date: new Date(),
168:           type: data.type,
169:           quantity: transactionQty,
170:           notes: data.notes || null,
171:           supplierId: data.supplierId || null,
172:         }
173:       });
174: 
175:       // 2. Actualizar stock actual en el item
176:       const updatedItem = await tx.inventory.update({
177:         where: { id: data.inventoryId },
178:         data: { currentStock: newStock }
179:       });
180: 
181:       await createAuditLog('inventory_transactions', transaction.id, 'insert', null, transaction);
182:       await createAuditLog('inventory', item.id, 'update', item, updatedItem);
183: 
184:       return { success: true, item: updatedItem };
185:     });
186:   } catch (error: any) {
187:     console.error('Error al registrar transacción de stock:', error);
188:     return { success: false, error: error.message || 'Error al registrar transacción' };
189:   }
190: }
